/**
 * OpenClaw 任务编排系统 v7.0
 * 模块5: 子代理进度上报
 * 
 * 功能:
 * - 自适应心跳间隔: 根据任务复杂度动态调整心跳频率
 * - 输出解析容错: 健壮的正则解析，支持多种格式
 * - 限流与聚合: 避免刷屏，聚合短时间内的多次更新
 * 
 * 存放位置: ~/.openclaw/workspace/skills/task-orchestrator-v7/
 */

import EventEmitter from 'events';

/**
 * 进度解析结果
 * @typedef {Object} ProgressParseResult
 * @property {number} percent - 进度百分比 (0-100)
 * @property {number} step - 当前步骤
 * @property {number} total - 总步骤数
 * @property {string} description - 步骤描述
 * @property {boolean} valid - 是否有效解析
 */

/**
 * 心跳状态
 * @typedef {Object} HeartbeatState
 * @property {number} lastHeartbeat - 上次心跳时间戳
 * @property {number} interval - 当前心跳间隔(ms)
 * @property {number} missedCount - 连续 missed 次数
 */

class ProgressReporter extends EventEmitter {
  constructor(options = {}) {
    super();

    // 配置
    this.config = {
      // 基础心跳间隔 (ms)
      baseInterval: options.baseInterval || 30000,
      // 最小心跳间隔 (ms)
      minInterval: options.minInterval || 5000,
      // 最大心跳间隔 (ms)
      maxInterval: options.maxInterval || 120000,
      // 自适应系数 (任务越复杂，心跳越频繁)
      complexityFactor: options.complexityFactor || 1.5,
      // 输出限流间隔 (ms) - 同一任务的多次进度更新会被聚合
      throttleInterval: options.throttleInterval || 1000,
      // 无产出警告阈值 (ms)
      noOutputWarning: options.noOutputWarning || 30000,
      // 无产出强制终止阈值 (ms)
      noOutputKill: options.noOutputKill || 60000,
      // 进度上报目标
      reportTarget: options.reportTarget || 'parent'
    };

    // 任务状态追踪
    this.taskStates = new Map();

    // 进度解析正则表达式 (支持多种格式)
    this.progressRegexes = [
      // 格式: [PROGRESS] 50% | 3/6 | 步骤描述
      /\[PROGRESS\]\s*(\d+)%\s*\|\s*(\d+)\/(\d+)\s*\|\s*(.+)/i,
      // 格式: PROGRESS: 50% (step 3/6)
      /PROGRESS:\s*(\d+)%\s*\(step\s*(\d+)\/(\d+)\)/i,
      // 格式: progress: 50%
      /progress:\s*(\d+)%/i,
      // 格式: [50%] Step 3 of 6: Doing something
      /\[(\d+)%\]\s*Step\s*(\d+)\s*of\s*(\d+):\s*(.+)/i,
      // 格式: 50% done (3/6)
      /(\d+)%\s*done\s*\((\d+)\/(\d+)\)/i
    ];

    // 聚合缓冲区
    this.throttleBuffer = new Map();
    this.throttleTimers = new Map();

    // 统计
    this.stats = {
      totalTasks: 0,
      completedTasks: 0,
      failedTasks: 0,
      heartbeatsSent: 0,
      parsesAttempted: 0,
      parsesSuccess: 0
    };
  }

  /**
   * 注册一个新任务
   * @param {string} taskId - 任务ID
   * @param {Object} options - 任务选项
   * @param {number} options.complexity - 任务复杂度 (1-10)
   * @param {number} options.totalSteps - 总步骤数
   * @param {Function} options.onHeartbeat - 心跳回调
   * @param {Function} options.onNoOutput - 无产出回调
   */
  registerTask(taskId, options = {}) {
    const complexity = options.complexity || 5;

    // 根据复杂度计算自适应心跳间隔
    const adaptiveInterval = Math.max(
      this.config.minInterval,
      Math.min(
        this.config.maxInterval,
        this.config.baseInterval / Math.pow(complexity, this.config.complexityFactor - 1)
      )
    );

    const state = {
      taskId,
      complexity,
      totalSteps: options.totalSteps || 1,
      currentStep: 0,
      percent: 0,
      description: '',
      startTime: Date.now(),
      lastOutputTime: Date.now(),
      lastHeartbeat: Date.now(),
      currentInterval: adaptiveInterval,
      heartbeatTimer: null,
      noOutputTimer: null,
      onHeartbeat: options.onHeartbeat || (() => {}),
      onNoOutput: options.onNoOutput || (() => {})
    };

    this.taskStates.set(taskId, state);
    this.stats.totalTasks++;

    // 启动心跳定时器
    this._startHeartbeat(taskId);

    // 启动无产出检测
    this._startNoOutputMonitor(taskId);

    return state;
  }

  /**
   * 注销任务
   * @param {string} taskId - 任务ID
   * @param {boolean} success - 是否成功完成
   */
  unregisterTask(taskId, success = false) {
    const state = this.taskStates.get(taskId);
    if (!state) return;

    // 清理定时器
    if (state.heartbeatTimer) clearInterval(state.heartbeatTimer);
    if (state.noOutputTimer) clearTimeout(state.noOutputTimer);

    // 更新统计
    if (success) {
      this.stats.completedTasks++;
    } else {
      this.stats.failedTasks++;
    }

    this.taskStates.delete(taskId);

    // 清理聚合缓冲
    if (this.throttleTimers.has(taskId)) {
      clearTimeout(this.throttleTimers.get(taskId));
      this.throttleTimers.delete(taskId);
    }
  }

  /**
   * 处理任务输出
   * @param {string} taskId - 任务ID
   * @param {string} output - 输出内容
   */
  handleOutput(taskId, output) {
    const state = this.taskStates.get(taskId);
    if (!state) return null;

    // 更新最后输出时间
    state.lastOutputTime = Date.now();

    // 解析进度
    const parsed = this.parseProgress(output);

    if (parsed && parsed.valid) {
      // 更新状态
      const oldPercent = state.percent;
      state.percent = parsed.percent;
      state.currentStep = parsed.step;
      state.totalSteps = parsed.total;
      state.description = parsed.description;

      // 检查是否需要调整心跳间隔
      if (parsed.percent > oldPercent) {
        this._adjustHeartbeatInterval(taskId);
      }

      // 触发限流上报
      this._throttledReport(taskId, parsed);
    }

    return parsed;
  }

  /**
   * 解析进度信息
   * @param {string} output - 输出内容
   * @returns {ProgressParseResult}
   */
  parseProgress(output) {
    this.stats.parsesAttempted++;

    if (!output || typeof output !== 'string') {
      return { valid: false };
    }

    for (const regex of this.progressRegexes) {
      const match = output.match(regex);
      if (match) {
        this.stats.parsesSuccess++;

        // 提取数据
        let percent, step, total, description;

        if (match.length === 5) {
          // [PROGRESS] 50% | 3/6 | 描述
          [, percent, step, total, description] = match;
        } else if (match.length === 4) {
          // PROGRESS: 50% (step 3/6) 或 [50%] Step 3 of 6: 描述
          [, percent, step, total, description] = match;
        } else if (match.length === 2) {
          // progress: 50%
          [, percent] = match;
          step = 0;
          total = 1;
          description = 'Processing...';
        } else if (match.length === 4) {
          // 50% done (3/6)
          [, percent, step, total] = match;
          description = 'In progress';
        }

        return {
          percent: Math.min(100, Math.max(0, parseInt(percent, 10) || 0)),
          step: parseInt(step, 10) || 1,
          total: parseInt(total, 10) || 1,
          description: (description || '').trim(),
          valid: true
        };
      }
    }

    return { valid: false };
  }

  /**
   * 获取任务当前状态
   * @param {string} taskId - 任务ID
   * @returns {Object|null}
   */
  getTaskState(taskId) {
    const state = this.taskStates.get(taskId);
    if (!state) return null;

    return {
      taskId: state.taskId,
      percent: state.percent,
      currentStep: state.currentStep,
      totalSteps: state.totalSteps,
      description: state.description,
      elapsed: Date.now() - state.startTime,
      sinceLastOutput: Date.now() - state.lastOutputTime
    };
  }

  /**
   * 获取所有活动任务
   * @returns {Array}
   */
  getActiveTasks() {
    return Array.from(this.taskStates.keys());
  }

  /**
   * 获取统计信息
   * @returns {Object}
   */
  getStats() {
    return { ...this.stats };
  }

  /**
   * 重置统计
   */
  resetStats() {
    this.stats = {
      totalTasks: 0,
      completedTasks: 0,
      failedTasks: 0,
      heartbeatsSent: 0,
      parsesAttempted: 0,
      parsesSuccess: 0
    };
  }

  // ============ 私有方法 ============

  /**
   * 启动心跳
   */
  _startHeartbeat(taskId) {
    const state = this.taskStates.get(taskId);
    if (!state) return;

    state.heartbeatTimer = setInterval(() => {
      this._sendHeartbeat(taskId);
    }, state.currentInterval);
  }

  /**
   * 发送心跳
   */
  _sendHeartbeat(taskId) {
    const state = this.taskStates.get(taskId);
    if (!state) return;

    state.lastHeartbeat = Date.now();
    state.onHeartbeat({
      taskId,
      percent: state.percent,
      elapsed: Date.now() - state.startTime,
      description: state.description
    });

    this.stats.heartbeatsSent++;
    this.emit('heartbeat', state.taskId, this.getTaskState(taskId));
  }

  /**
   * 启动无产出监控
   */
  _startNoOutputMonitor(taskId) {
    const state = this.taskStates.get(taskId);
    if (!state) return;

    // 定期检查无产出
    state.noOutputTimer = setInterval(() => {
      const now = Date.now();
      const sinceOutput = now - state.lastOutputTime;

      if (sinceOutput >= this.config.noOutputKill) {
        // 强制终止
        state.onNoOutput('kill', sinceOutput);
        this.emit('noOutput', taskId, 'kill', sinceOutput);
        this.unregisterTask(taskId, false);
      } else if (sinceOutput >= this.config.noOutputWarning) {
        // 警告
        state.onNoOutput('warning', sinceOutput);
        this.emit('noOutput', taskId, 'warning', sinceOutput);
      }
    }, 5000); // 每5秒检查一次
  }

  /**
   * 调整心跳间隔
   */
  _adjustHeartbeatInterval(taskId) {
    const state = this.taskStates.get(taskId);
    if (!state) return;

    // 根据进度百分比动态调整
    // 进度越快，调整越频繁
    const progressRate = state.percent / Math.max(1, (Date.now() - state.startTime) / 1000);

    // 如果进度较快，加快心跳
    if (progressRate > 0.1) {
      state.currentInterval = Math.max(
        this.config.minInterval,
        state.currentInterval * 0.8
      );
    } else if (progressRate < 0.01) {
      // 进度慢，减少心跳频率
      state.currentInterval = Math.min(
        this.config.maxInterval,
        state.currentInterval * 1.2
      );
    }

    // 重新设置心跳定时器
    if (state.heartbeatTimer) {
      clearInterval(state.heartbeatTimer);
      this._startHeartbeat(taskId);
    }
  }

  /**
   * 限流上报
   */
  _throttledReport(taskId, parsed) {
    // 检查是否已有缓冲
    if (this.throttleBuffer.has(taskId)) {
      // 更新缓冲数据（不立即上报）
      this.throttleBuffer.set(taskId, parsed);
      return;
    }

    // 立即上报并设置缓冲
    this.throttleBuffer.set(taskId, parsed);
    this.emit('progress', taskId, parsed);

    // 设置定时器清理缓冲
    const timer = setTimeout(() => {
      const buffered = this.throttleBuffer.get(taskId);
      if (buffered) {
        this.throttleBuffer.delete(taskId);
        this.throttleTimers.delete(taskId);
      }
    }, this.config.throttleInterval);

    this.throttleTimers.set(taskId, timer);
  }
}

