/**
 * OpenClaw 任务编排系统 v7.0
 * 模块6: 安全模块
 * 
 * 功能:
 * - 命令白名单动态管理: 可配置允许执行的命令列表
 * - 路径沙箱: 限制文件访问范围，防止目录穿越
 * - 敏感信息脱敏: 自动识别并脱敏输出中的敏感信息
 * 
 * 存放位置: ~/.openclaw/workspace/skills/task-orchestrator-v7/
 */

import * as path from 'path';
import * as fs from 'fs';

/**
 * 安全检查结果
 * @typedef {Object} SecurityCheckResult
 * @property {boolean} allowed - 是否允许执行
 * @property {string} reason - 拒绝原因
 * @property {string} [sanitized] - 脱敏后的内容
 */

class SecurityModule {
  constructor(options = {}) {
    // 配置
    this.config = {
      // 默认允许的命令白名单
      allowedCommands: options.allowedCommands || [
        'node', 'npm', 'npx', 'yarn', 'pnpm',
        'python', 'python3', 'pip', 'pip3',
        'git', 'docker', 'docker-compose',
        'ls', 'cat', 'grep', 'find', 'awk', 'sed',
        'curl', 'wget', 'tar', 'zip', 'unzip',
        'node', 'ts-node', 'deno', 'bun',
        'echo', 'printf', 'env', 'pwd'
      ],
      // 禁止的命令黑名单
      blockedCommands: options.blockedCommands || [
        'rm', 'rmdir', 'del', 'rd',
        'mkfs', 'fsck', 'dd', 'fdisk',
        'sudo', 'su', 'chmod', 'chown', 'chgrp',
        'shutdown', 'reboot', 'poweroff', 'halt',
        'iptables', 'ufw', 'firewall-cmd',
        'passwd', 'shadow',
        'nc', 'netcat', 'ncat',
        'eval', 'exec', 'source', '.'
      ],
      // 沙箱根目录 (默认工作目录)
      sandboxRoot: options.sandboxRoot || process.cwd(),
      // 是否启用沙箱
      enableSandbox: options.enableSandbox !== false,
      // 敏感信息模式
      sensitivePatterns: options.sensitivePatterns || this._defaultSensitivePatterns(),
      // 脱敏替换字符串
      maskString: options.maskString || '[REDACTED]',
      // 允许的文件扩展名
      allowedExtensions: options.allowedExtensions || [
        '.js', '.ts', '.py', '.json', '.yml', '.yaml', '.md',
        '.txt', '.csv', '.html', '.css', '.scss', '.less',
        '.sh', '.bash', '.zsh',
        '.jpg', '.png', '.gif', '.webp', '.svg'
      ]
    };

    // 白名单缓存
    this.commandWhitelist = new Set(this.config.allowedCommands);
    this.commandBlacklist = new Set(this.config.blockedCommands);

    // 统计
    this.stats = {
      checksPerformed: 0,
      blockedCommands: 0,
      blockedPaths: 0,
      sensitiveDetected: 0
    };
  }

  /**
   * 检查命令是否允许执行
   * @param {string} command - 要检查的命令
   * @returns {SecurityCheckResult}
   */
  checkCommand(command) {
    this.stats.checksPerformed++;

    if (!command || typeof command !== 'string') {
      return { allowed: false, reason: 'Invalid command format' };
    }

    // 提取命令的基础名称
    const cmdBase = command.trim().split(/\s+/)[0].toLowerCase();

    // 检查黑名单
    if (this.commandBlacklist.has(cmdBase)) {
      this.stats.blockedCommands++;
      return { allowed: false, reason: `Command '${cmdBase}' is blocked by security policy` };
    }

    // 检查白名单
    if (!this.commandWhitelist.has(cmdBase)) {
      this.stats.blockedCommands++;
      return { allowed: false, reason: `Command '${cmdBase}' is not in the allowed list` };
    }

    // 检查命令中是否包含危险操作符
    const dangerousOperators = [';', '&&', '||', '|', '>', '>>', '<', '<<', '`', '$('];
    for (const op of dangerousOperators) {
      if (command.includes(op)) {
        return { allowed: false, reason: `Command contains dangerous operator '${op}'` };
      }
    }

    return { allowed: true, reason: 'Command allowed' };
  }

  /**
   * 检查路径是否在沙箱范围内
   * @param {string} filePath - 要检查的文件路径
   * @returns {SecurityCheckResult}
   */
  checkPath(filePath) {
    this.stats.checksPerformed++;

    if (!this.config.enableSandbox) {
      return { allowed: true, reason: 'Sandbox is disabled' };
    }

    if (!filePath || typeof filePath !== 'string') {
      return { allowed: false, reason: 'Invalid path format' };
    }

    try {
      // 解析绝对路径
      const absolutePath = path.resolve(filePath);
      const sandboxRoot = path.resolve(this.config.sandboxRoot);

      // 检查是否在沙箱目录下
      if (!absolutePath.startsWith(sandboxRoot + path.sep) && absolutePath !== sandboxRoot) {
        this.stats.blockedPaths++;
        return { allowed: false, reason: `Path '${filePath}' is outside the sandbox root '${this.config.sandboxRoot}'` };
      }

      // 检查文件扩展名
      const ext = path.extname(absolutePath).toLowerCase();
      if (ext && !this.config.allowedExtensions.includes(ext)) {
        return { allowed: false, reason: `File extension '${ext}' is not allowed` };
      }

      return { allowed: true, reason: 'Path allowed' };
    } catch (e) {
      return { allowed: false, reason: `Invalid path: ${e.message}` };
    }
  }

  /**
   * 脱敏敏感信息
   * @param {string} content - 要脱敏的内容
   * @returns {SecurityCheckResult}
   */
  desensitize(content) {
    if (!content || typeof content !== 'string') {
      return { allowed: true, sanitized: content || '' };
    }

    let sanitized = content;
    let detectedCount = 0;

    for (const [name, pattern] of Object.entries(this.config.sensitivePatterns)) {
      const matches = sanitized.match(pattern);
      if (matches) {
        detectedCount += matches.length;
        sanitized = sanitized.replace(pattern, this.config.maskString);
      }
    }

    this.stats.sensitiveDetected += detectedCount;

    return {
      allowed: true,
      sanitized,
      detectedCount,
      reason: detectedCount > 0 ? `Desensitized ${detectedCount} sensitive entries` : 'No sensitive content detected'
    };
  }

  /**
   * 完整安全检查 (命令 + 路径 + 内容脱敏)
   * @param {string} command - 命令
   * @param {Array<string>} paths - 涉及的路径
   * @param {string} output - 输出内容
   * @returns {Object}
   */
  fullCheck(command = null, paths = [], output = null) {
    const result = {
      allowed: true,
      commandCheck: null,
      pathChecks: [],
      desensitizeResult: null,
      finalOutput: output
    };

    // 检查命令
    if (command) {
      result.commandCheck = this.checkCommand(command);
      if (!result.commandCheck.allowed) {
        result.allowed = false;
      }
    }

    // 检查路径
    for (const p of paths) {
      const pathCheck = this.checkPath(p);
      result.pathChecks.push({ path: p, result: pathCheck });
      if (!pathCheck.allowed) {
        result.allowed = false;
      }
    }

    // 脱敏输出
    if (output) {
      result.desensitizeResult = this.desensitize(output);
      result.finalOutput = result.desensitizeResult.sanitized;
    }

    return result;
  }

  /**
   * 动态添加允许的命令
   * @param {string|Array<string>} commands - 要添加的命令
   */
  addAllowedCommands(commands) {
    const cmdArray = Array.isArray(commands) ? commands : [commands];
    for (const cmd of cmdArray) {
      this.commandWhitelist.add(cmd.toLowerCase());
    }
  }

  /**
   * 移除允许的命令
   * @param {string|Array<string>} commands - 要移除的命令
   */
  removeAllowedCommands(commands) {
    const cmdArray = Array.isArray(commands) ? commands : [commands];
    for (const cmd of cmdArray) {
      this.commandWhitelist.delete(cmd.toLowerCase());
    }
  }

  /**
   * 添加敏感信息匹配模式
   * @param {string} name - 模式名称
   * @param {RegExp} pattern - 正则表达式
   */
  addSensitivePattern(name, pattern) {
    if (pattern instanceof RegExp) {
      this.config.sensitivePatterns[name] = pattern;
    }
  }

  /**
   * 设置沙箱根目录
   * @param {string} rootPath - 沙箱根目录
   */
  setSandboxRoot(rootPath) {
    try {
      const absolutePath = path.resolve(rootPath);
      if (fs.existsSync(absolutePath) && fs.statSync(absolutePath).isDirectory()) {
        this.config.sandboxRoot = absolutePath;
        return { success: true };
      }
      return { success: false, error: 'Path does not exist or is not a directory' };
    } catch (e) {
      return { success: false, error: e.message };
    }
  }

  /**
   * 获取当前安全配置
   * @returns {Object}
   */
  getConfig() {
    return {
      allowedCommands: Array.from(this.commandWhitelist),
      blockedCommands: Array.from(this.commandBlacklist),
      sandboxRoot: this.config.sandboxRoot,
      enableSandbox: this.config.enableSandbox,
      allowedExtensions: [...this.config.allowedExtensions]
    };
  }

  /**
   * 获取统计信息
   * @returns {Object}
   */
  getStats() {
    return { ...this.stats };
  }

  /**
   * 重置统计
   */
  resetStats() {
    this.stats = {
      checksPerformed: 0,
      blockedCommands: 0,
      blockedPaths: 0,
      sensitiveDetected: 0
    };
  }

  // ============ 私有方法 ============

  /**
   * 默认敏感信息匹配模式
   * @private
   */
  _defaultSensitivePatterns() {
    return {
      // API密钥
      apiKey: /\b(sk|api|key|token|secret|password|passwd|pwd)_[a-zA-Z0-9]{10,}\b/gi,
      // 通用密钥
      bearerToken: /\bbearer\s+[a-zA-Z0-9._-]{20,}\b/gi,
      // JWT令牌
      jwt: /\bey[A-Za-z0-9_-]{20,}\.[A-Za-z0-9_-]{20,}\.[A-Za-z0-9_-]{20,}\b/gi,
      // 邮箱地址
      email: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/gi,
      // 手机号 (中国)
      phone: /\b1[3-9]\d{9}\b/gi,
      // IP地址
      ipAddress: /\b(?:\d{1,3}\.){3}\d{1,3}\b/gi,
      // 信用卡号
      creditCard: /\b(?:\d[ -]*?){13,16}\b/gi,
      // 身份证号 (中国)
      idCard: /\b[1-9]\d{5}(?:18|19|20)\d{2}(?:0[1-9]|1[012])(?:0[1-9]|[12]\d|3[01])\d{3}[\dXx]\b/gi,
      // AWS密钥
      awsKey: /\bAKIA[0-9A-Z]{16}\b/gi,
      // 私钥片段
      privateKey: /-----BEGIN (?:RSA|EC|DSA|OPENSSH) PRIVATE KEY-----[\s\S]+?-----END (?:RSA|EC|DSA|OPENSSH) PRIVATE KEY-----/gi
    };
  }
}

