export { SecurityModule };

/**
 * OpenClaw 任务编排系统 v7.0
 * 模块7: 效率优化模块
 * 
 * 功能:
 * - 评分缓存: 缓存相似任务的评分结果，减少重复计算
 * - 异步日志: 非阻塞日志写入，避免IO阻塞
 * - 连接池管理: 复用数据库/API连接，减少连接开销
 * 
 * 存放位置: ~/.openclaw/workspace/skills/task-orchestrator-v7/
 */

import * as fs from 'fs';
import * as path from 'path';
import { createHash } from 'crypto';
import { EventEmitter } from 'events';

/**
 * 缓存条目
 * @typedef {Object} CacheEntry
 * @property {any} value - 缓存值
 * @property {number} timestamp - 缓存时间戳
 * @property {number} ttl - 过期时间(ms)
 * @property {number} hits - 命中次数
 */

/**
 * 日志级别
 * @typedef {'debug' | 'info' | 'warn' | 'error'} LogLevel
 */

/**
 * 日志条目
 * @typedef {Object} LogEntry
 * @property {LogLevel} level - 日志级别
 * @property {string} message - 日志消息
 * @property {Object} [metadata] - 元数据
 * @property {number} timestamp - 时间戳
 */

class OptimizerModule extends EventEmitter {
  constructor(options = {}) {
    super();

    // 配置
    this.config = {
      // 缓存配置
      cacheMaxSize: options.cacheMaxSize || 1000,
      defaultCacheTTL: options.defaultCacheTTL || 3600000, // 1小时
      cacheEnabled: options.cacheEnabled !== false,

      // 日志配置
      logLevel: options.logLevel || 'info',
      logDir: options.logDir || path.join(process.cwd(), 'logs'),
      logFilePrefix: options.logFilePrefix || 'orchestrator',
      logMaxFileSize: options.logMaxFileSize || 10 * 1024 * 1024, // 10MB
      logMaxFiles: options.logMaxFiles || 7,
      asyncLogBatchSize: options.asyncLogBatchSize || 100,
      asyncLogFlushInterval: options.asyncLogFlushInterval || 1000, // 1秒

      // 连接池配置
      connectionPoolMaxSize: options.connectionPoolMaxSize || 10,
      connectionIdleTimeout: options.connectionIdleTimeout || 30000 // 30秒
    };

    // 评分缓存 (LRU)
    this.scoreCache = new Map();

    // 异步日志缓冲区
    this.logBuffer = [];
    this.logFlushTimer = null;
    this.currentLogFile = null;
    this.currentLogFileSize = 0;

    // 连接池
    this.connectionPools = new Map();

    // 统计
    this.stats = {
      cacheHits: 0,
      cacheMisses: 0,
      cacheSize: 0,
      logsWritten: 0,
      logsDropped: 0,
      connectionsCreated: 0,
      connectionsReused: 0,
      connectionsClosed: 0
    };

    // 初始化
    this._init();
  }

  /**
   * 获取评分缓存
   * @param {string} key - 缓存键
   * @returns {any|null} 缓存值，不存在或过期返回null
   */
  getScoreCache(key) {
    if (!this.config.cacheEnabled) return null;

    const entry = this.scoreCache.get(key);
    if (!entry) {
      this.stats.cacheMisses++;
      return null;
    }

    // 检查是否过期
    if (entry.timestamp + entry.ttl < Date.now()) {
      this.scoreCache.delete(key);
      this.stats.cacheMisses++;
      return null;
    }

    // 更新命中次数
    entry.hits++;
    this.stats.cacheHits++;

    // 移动到末尾 (LRU策略)
    this.scoreCache.delete(key);
    this.scoreCache.set(key, entry);

    return entry.value;
  }

  /**
   * 设置评分缓存
   * @param {string} key - 缓存键
   * @param {any} value - 缓存值
   * @param {number} [ttl] - 过期时间(ms)，默认使用defaultCacheTTL
   */
  setScoreCache(key, value, ttl = null) {
    if (!this.config.cacheEnabled) return;

    const entry = {
      value,
      timestamp: Date.now(),
      ttl: ttl || this.config.defaultCacheTTL,
      hits: 0
    };

    // 如果缓存已满，删除最旧的条目
    if (this.scoreCache.size >= this.config.cacheMaxSize) {
      const oldestKey = this.scoreCache.keys().next().value;
      this.scoreCache.delete(oldestKey);
    }

    this.scoreCache.set(key, entry);
    this.stats.cacheSize = this.scoreCache.size;
  }

  /**
   * 根据任务特征生成缓存键
   * @param {Object} taskSpec - 任务规范
   * @returns {string} 缓存键
   */
  generateCacheKey(taskSpec) {
    // 提取关键特征生成哈希
    const features = {
      type: taskSpec.type || 'default',
      instruction: taskSpec.instruction?.slice(0, 1000) || '',
      codeLines: taskSpec.codeLines || 0,
      dependencyCount: taskSpec.dependencyCount || 0,
      complexity: taskSpec.complexity || 0
    };

    const hash = createHash('md5')
      .update(JSON.stringify(features))
      .digest('hex');

    return `score:${hash}`;
  }

  /**
   * 清除过期缓存
   * @returns {number} 清除的条目数
   */
  cleanupExpiredCache() {
    const now = Date.now();
    let count = 0;

    for (const [key, entry] of this.scoreCache.entries()) {
      if (entry.timestamp + entry.ttl < now) {
        this.scoreCache.delete(key);
        count++;
      }
    }

    this.stats.cacheSize = this.scoreCache.size;
    return count;
  }

  /**
   * 清空所有缓存
   */
  clearCache() {
    this.scoreCache.clear();
    this.stats.cacheSize = 0;
  }

  /**
   * 记录日志 (异步)
   * @param {LogLevel} level - 日志级别
   * @param {string} message - 日志消息
   * @param {Object} [metadata] - 元数据
   */
  log(level, message, metadata = null) {
    const logLevels = ['debug', 'info', 'warn', 'error'];
    const levelIndex = logLevels.indexOf(level);
    const configLevelIndex = logLevels.indexOf(this.config.logLevel);

    // 低于配置级别的日志忽略
    if (levelIndex < configLevelIndex) return;

    const entry = {
      level,
      message,
      metadata,
      timestamp: Date.now()
    };

    // 添加到缓冲区
    this.logBuffer.push(entry);

    // 达到批量大小立即刷新
    if (this.logBuffer.length >= this.config.asyncLogBatchSize) {
      this._flushLogs();
    } else if (!this.logFlushTimer) {
      // 设置定时器刷新
      this.logFlushTimer = setTimeout(() => {
        this._flushLogs();
      }, this.config.asyncLogFlushInterval);
    }
  }

  /**
   * 便捷日志方法
   */
  debug(message, metadata = null) {
    this.log('debug', message, metadata);
  }

  info(message, metadata = null) {
    this.log('info', message, metadata);
  }

  warn(message, metadata = null) {
    this.log('warn', message, metadata);
  }

  error(message, metadata = null) {
    this.log('error', message, metadata);
  }

  /**
   * 强制刷新日志缓冲区
   * @returns {Promise<number>} 写入的日志条数
   */
  async flushLogs() {
    return this._flushLogs();
  }

  /**
   * 从连接池获取连接
   * @param {string} poolName - 连接池名称
   * @param {Function} createConnection - 创建新连接的函数
   * @returns {Promise<any>} 连接实例
   */
  async getConnection(poolName, createConnection) {
    let pool = this.connectionPools.get(poolName);
    if (!pool) {
      pool = {
        connections: [],
        waiting: [],
        maxSize: this.config.connectionPoolMaxSize
      };
      this.connectionPools.set(poolName, pool);
    }

    // 查找可用连接
    while (pool.connections.length > 0) {
      const conn = pool.connections.shift();
      if (conn.lastUsed + this.config.connectionIdleTimeout > Date.now()) {
        // 连接有效
        conn.lastUsed = Date.now();
        this.stats.connectionsReused++;
        return conn.instance;
      }
      // 连接已过期，关闭
      this._closeConnection(poolName, conn);
    }

    // 没有可用连接，检查是否可以创建新连接
    const totalConnections = pool.connections.length + (pool.waiting ? pool.waiting.length : 0);
    if (totalConnections < pool.maxSize) {
      // 创建新连接
      this.stats.connectionsCreated++;
      const instance = await createConnection();
      return instance;
    }

    // 连接池已满，等待
    return new Promise(resolve => {
      pool.waiting.push(resolve);
    });
  }

  /**
   * 释放连接回连接池
   * @param {string} poolName - 连接池名称
   * @param {any} connection - 连接实例
   */
  releaseConnection(poolName, connection) {
    const pool = this.connectionPools.get(poolName);
    if (!pool) return;

    const connEntry = {
      instance: connection,
      lastUsed: Date.now()
    };

    // 检查是否有等待的请求
    if (pool.waiting.length > 0) {
      const resolve = pool.waiting.shift();
      this.stats.connectionsReused++;
      resolve(connection);
      return;
    }

    // 放回连接池
    pool.connections.push(connEntry);
  }

  /**
   * 清理过期连接
   * @returns {number} 清理的连接数
   */
  cleanupIdleConnections() {
    const now = Date.now();
    let count = 0;

    for (const [poolName, pool] of this.connectionPools.entries()) {
      const validConnections = [];

      for (const conn of pool.connections) {
        if (conn.lastUsed + this.config.connectionIdleTimeout > now) {
          validConnections.push(conn);
        } else {
          this._closeConnection(poolName, conn);
          count++;
        }
      }

      pool.connections = validConnections;
    }

    return count;
  }

  /**
   * 获取统计信息
   * @returns {Object}
   */
  getStats() {
    return {
      ...this.stats,
      cacheHitRate: this.stats.cacheHits / Math.max(1, this.stats.cacheHits + this.stats.cacheMisses),
      currentCacheSize: this.scoreCache.size,
      pendingLogs: this.logBuffer.length
    };
  }

  /**
   * 重置统计
   */
  resetStats() {
    this.stats = {
      cacheHits: 0,
      cacheMisses: 0,
      cacheSize: 0,
      logsWritten: 0,
      logsDropped: 0,
      connectionsCreated: 0,
      connectionsReused: 0,
      connectionsClosed: 0
    };
  }

  /**
   * 关闭所有连接和资源
   * @returns {Promise<void>}
   */
  async shutdown() {
    // 刷新日志
    await this._flushLogs();

    // 关闭所有连接
    for (const [poolName, pool] of this.connectionPools.entries()) {
      for (const conn of pool.connections) {
        this._closeConnection(poolName, conn);
      }
    }

    // 清除定时器
    if (this.logFlushTimer) {
      clearTimeout(this.logFlushTimer);
      this.logFlushTimer = null;
    }

    // 关闭日志文件
    if (this.currentLogFile) {
      await fs.promises.close(this.currentLogFile);
      this.currentLogFile = null;
    }
  }

  // ============ 私有方法 ============

  /**
   * 初始化
   * @private
   */
  async _init() {
    // 创建日志目录
    try {
      await fs.promises.mkdir(this.config.logDir, { recursive: true });
    } catch (e) {
      console.warn('Failed to create log directory:', e.message);
    }

    // 启动定期清理任务
    setInterval(() => {
      this.cleanupExpiredCache();
      this.cleanupIdleConnections();
    }, 60000); // 每分钟清理一次
  }

  /**
   * 刷新日志缓冲区到文件
   * @private
   */
  async _flushLogs() {
    if (this.logBuffer.length === 0) return 0;

    // 清除定时器
    if (this.logFlushTimer) {
      clearTimeout(this.logFlushTimer);
      this.logFlushTimer = null;
    }

    const logs = this.logBuffer.splice(0, this.config.asyncLogBatchSize);

    try {
      // 确保日志文件可用
      await this._ensureLogFile();

      // 格式化日志
      const logLines = logs.map(entry => this._formatLogEntry(entry)).join('\n') + '\n';
      const buffer = Buffer.from(logLines, 'utf8');

      // 写入文件
      await fs.promises.write(this.currentLogFile, buffer, 0, buffer.length, this.currentLogFileSize);
      this.currentLogFileSize += buffer.length;
      this.stats.logsWritten += logs.length;

      // 检查是否需要轮转日志
      if (this.currentLogFileSize >= this.config.logMaxFileSize) {
        await this._rotateLogs();
      }

      return logs.length;
    } catch (e) {
      console.error('Failed to write logs:', e.message);
      this.stats.logsDropped += logs.length;
      return 0;
    }
  }

  /**
   * 确保日志文件已打开
   * @private
   */
  async _ensureLogFile() {
    if (this.currentLogFile) return;

    const dateStr = new Date().toISOString().split('T')[0];
    const logFileName = `${this.config.logFilePrefix}-${dateStr}.log`;
    const logFilePath = path.join(this.config.logDir, logFileName);

    // 打开文件 (追加模式)
    this.currentLogFile = await fs.promises.open(logFilePath, 'a');

    // 获取当前文件大小
    const stats = await fs.promises.stat(logFilePath);
    this.currentLogFileSize = stats.size;
  }

  /**
   * 日志轮转
   * @private
   */
  async _rotateLogs() {
    // 关闭当前文件
    if (this.currentLogFile) {
      await fs.promises.close(this.currentLogFile);
      this.currentLogFile = null;
    }

    // 列出所有日志文件
    const files = await fs.promises.readdir(this.config.logDir);
    const logFiles = files
      .filter(f => f.startsWith(this.config.logFilePrefix) && f.endsWith('.log'))
      .sort()
      .reverse();

    // 删除超过最大数量的旧文件
    if (logFiles.length >= this.config.logMaxFiles) {
      for (let i = this.config.logMaxFiles - 1; i < logFiles.length; i++) {
        try {
          await fs.promises.unlink(path.join(this.config.logDir, logFiles[i]));
        } catch (e) {
          // 忽略删除错误
        }
      }
    }
  }

  /**
   * 格式化日志条目
   * @private
   */
  _formatLogEntry(entry) {
    const timestamp = new Date(entry.timestamp).toISOString();
    const metadataStr = entry.metadata ? ` ${JSON.stringify(entry.metadata)}` : '';
    return `[${timestamp}] [${entry.level.toUpperCase()}] ${entry.message}${metadataStr}`;
  }

  /**
   * 关闭连接
   * @private
   */
  _closeConnection(poolName, conn) {
    try {
      if (typeof conn.instance.close === 'function') {
        conn.instance.close();
      } else if (typeof conn.instance.end === 'function') {
        conn.instance.end();
      } else if (typeof conn.instance.destroy === 'function') {
        conn.instance.destroy();
      }
      this.stats.connectionsClosed++;
    } catch (e) {
      // 忽略关闭错误
    }
  }
}

